import{_ as a,o as s,c as t,ag as n}from"./chunks/framework.BDReElpY.js";const h=JSON.parse('{"title":"Chapter 4: Core Concepts","description":"","frontmatter":{},"headers":[],"relativePath":"archive/guide/04_core_concepts.md","filePath":"archive/guide/04_core_concepts.md"}'),i={name:"archive/guide/04_core_concepts.md"};function o(l,e,p,c,r,d){return s(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="chapter-4-core-concepts" tabindex="-1">Chapter 4: Core Concepts <a class="header-anchor" href="#chapter-4-core-concepts" aria-label="Permalink to &quot;Chapter 4: Core Concepts&quot;">​</a></h1><p>Welcome to Vex. This guide will walk you through the core concepts of the language. Vex is designed to be familiar to users of Rust, Go, and TypeScript, but it has its own unique philosophy.</p><h2 id="_1-2-variables-and-mutability" tabindex="-1">1.2 Variables and Mutability <a class="header-anchor" href="#_1-2-variables-and-mutability" aria-label="Permalink to &quot;1.2 Variables and Mutability&quot;">​</a></h2><p>This is where Vex differs from many languages.</p><h3 id="immutable-by-default" tabindex="-1">Immutable by Default <a class="header-anchor" href="#immutable-by-default" aria-label="Permalink to &quot;Immutable by Default&quot;">​</a></h3><p>Variables declared with <code>let</code> are <strong>immutable</strong>. You cannot change them.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let x = 42;</span></span>
<span class="line"><span>// x = 100;</span><span> // Error!</span></span></code></pre></div><h3 id="explicit-mutability-let" tabindex="-1">Explicit Mutability (<code>let!</code>) <a class="header-anchor" href="#explicit-mutability-let" aria-label="Permalink to &quot;Explicit Mutability (\`let!\`)&quot;">​</a></h3><p>To make a variable mutable, you must use the <code>!</code> bang operator.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let! count = 0;</span></span>
<span class="line"><span>count = count + 1; // OK</span></span></code></pre></div><blockquote><p><strong>Why <code>!</code>?</strong> Vex emphasizes that mutation is a side-effect. The <code>!</code> serves as a visual marker that &quot;this value changes&quot;.</p></blockquote><h2 id="_1-3-basic-types" tabindex="-1">1.3 Basic Types <a class="header-anchor" href="#_1-3-basic-types" aria-label="Permalink to &quot;1.3 Basic Types&quot;">​</a></h2><p>Vex supports standard systems types:</p><ul><li><strong>Integers</strong>: <code>i32</code>, <code>u64</code>, <code>i8</code>, <code>usize</code>...</li><li><strong>Floats</strong>: <code>f32</code>, <code>f64</code></li><li><strong>Boolean</strong>: <code>bool</code> (<code>true</code>, <code>false</code>)</li><li><strong>String</strong>: <code>string</code> (UTF-8)</li></ul><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let age: i32 = 25;</span></span>
<span class="line"><span>let price: f64 = 19.99;</span></span>
<span class="line"><span>let is_active = true; // Type inferred</span></span></code></pre></div><h2 id="_1-4-functions" tabindex="-1">1.4 Functions <a class="header-anchor" href="#_1-4-functions" aria-label="Permalink to &quot;1.4 Functions&quot;">​</a></h2><p>Functions are first-class citizens.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn add(a: i32, b: i32): i32 {</span></span>
<span class="line"><span>    return a + b;</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="named-return-types-go-style-planned" tabindex="-1">Named Return Types (Go-style) - <em>Planned</em> <a class="header-anchor" href="#named-return-types-go-style-planned" aria-label="Permalink to &quot;Named Return Types (Go-style) - *Planned*&quot;">​</a></h3><p>Vex is exploring named returns, but current versions use standard return syntax.</p><h2 id="_1-5-comments" tabindex="-1">1.5 Comments <a class="header-anchor" href="#_1-5-comments" aria-label="Permalink to &quot;1.5 Comments&quot;">​</a></h2><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Single line comment</span></span>
<span class="line"><span></span></span>
<span class="line"><span>/*</span></span>
<span class="line"><span>   Multi-line</span></span>
<span class="line"><span>   Comment</span></span>
<span class="line"><span>*/</span></span></code></pre></div><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>Now that you know the basics, let&#39;s look at how Vex handles data with <strong>Structs</strong>.</p>`,24)])])}const b=a(i,[["render",o]]);export{h as __pageData,b as default};
